const raw = $input.first().json;
const a = raw.body || raw;
var phone = (a.customer?.phone || '').replace(/\+/g, '').replace(/ /g, '');
if (phone && !phone.startsWith('549') && !phone.startsWith('54') && phone.length <= 11) {
  phone = '549' + phone;
}
return [{
  json: {
    clientName: (a.customer?.firstName || '') + ' ' + (a.customer?.lastName || ''),
    phone: phone,
    service: a.service?.name || '',
    date: (a.start || '').split(' ')[0],
    time: ((a.start || '').split(' ')[1] || '').substring(0, 5)
  }
}];
